import { useState } from 'react';
import { createDestination } from '../services/api';

export default function CreateDestination({ onClose, onCreate }) {
    const [name, setName] = useState('');
    const [imageFile, setImageFile] = useState(null);
    const [price, setPrice] = useState('');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [creator, setCreator] = useState('');
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!name || !imageFile || !price || !startDate || !endDate || !creator) {
            setError('Tous les champs sont obligatoires.');
            return;
        }

        try {
            const formData = new FormData();
            formData.append('name', name);
            formData.append('image', imageFile);
            formData.append('price', price);
            formData.append('startDate', startDate);
            formData.append('endDate', endDate);
            formData.append('creator', creator);
            formData.append('members', JSON.stringify([]));
            formData.append('comments', JSON.stringify([]));

            const newDestination = await createDestination(formData); // doit retourner la nouvelle destination

            if (onCreate) onCreate(newDestination); // mise à jour immédiate dans Destinations.jsx
            onClose();
        } catch (err) {
            console.error(err);
            setError("Erreur lors de la création.");
        }
    };

    return (
        <form className="create-group-form" onSubmit={handleSubmit}>
            <h2>Nouvelle destination</h2>

            <label>Nom</label>
            <input value={name} onChange={(e) => setName(e.target.value)} required />

            <label>Image </label>
            <input
                type="file"
                accept="image/*"
                onChange={(e) => setImageFile(e.target.files[0])}
                required
            />

            <label>Prix (€)</label>
            <input type="number" value={price} onChange={(e) => setPrice(e.target.value)} required />

            <label>Date de début</label>
            <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} required />

            <label>Date de fin</label>
            <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} required />

            <label>Proposé par</label>
            <input type="text" value={creator} onChange={(e) => setCreator(e.target.value)} required />

            {error && <p className="login-error">{error}</p>}

            <button type="submit" className="create-group-button">
                Créer
            </button>
        </form>
    );
}
